"""
sync/e2e_crypto.py  (Django server)
=====================================
Server-side counterpart to the desktop's sync/crypto.py.

Handles:
  - Decrypting push payloads from the client
  - Encrypting pull responses back to the client

Protocol: X25519 ECDH + HKDF-SHA256 + AES-128-GCM  (same as client)

Django settings required
------------------------
Add to your settings.py (or settings/production.py):

    # Generated by keygen.py — keep this secret, never commit to VCS
    SYNC_E2E_PRIVATE_KEY = "UPMECf6fTh8upBjRy1ctHNhkm/wjAhhmt08miPgje2w="

    # Grace toggle: if True, non-encrypted requests are allowed through.
    # Set False in production once all clients have been updated.
    SYNC_E2E_REQUIRED = True

Key derivation (mirrors client exactly)
----------------------------------------
  shared_secret = ECDH(server_long_term_priv, client_ephemeral_pub)
  session_key   = HKDF-SHA256(shared_secret, salt=nonce, info=b"primebooks-sync-v1")
  plaintext     = AES-128-GCM.decrypt(ciphertext, session_key, nonce, tag)

Response encryption (pull)
---------------------------
  The server re-uses the client's ephemeral public key (from the request
  envelope/header) to derive the same session key, then encrypts the
  response with that key.  The client already has the matching private key
  so it can decrypt without any additional key exchange.

  This means both push responses AND pull responses are encrypted with
  the SAME session key that was established during the request, providing
  a clean request/response pair with a single ECDH handshake.
"""

from __future__ import annotations

import base64
import json
import logging
import os

from cryptography.hazmat.primitives.asymmetric.x25519 import (
    X25519PrivateKey,
    X25519PublicKey,
)
from cryptography.hazmat.primitives.ciphers.aead import AESGCM
from cryptography.hazmat.primitives.hashes import SHA256
from cryptography.hazmat.primitives.kdf.hkdf import HKDF
from cryptography.hazmat.primitives.serialization import (
    Encoding,
    PublicFormat,
    PrivateFormat,
    NoEncryption,
)

logger = logging.getLogger(__name__)

# Protocol constants — must match client
_PROTOCOL_VERSION = 1
_HKDF_INFO        = b"primebooks-sync-v1"
_NONCE_BYTES      = 12
_KEY_BYTES        = 16


# ─────────────────────────────────────────────────────────────────────────────
# Internal helpers
# ─────────────────────────────────────────────────────────────────────────────

def _b64e(data: bytes) -> str:
    return base64.b64encode(data).decode()


def _b64d(s: str) -> bytes:
    return base64.b64decode(s)


def _load_server_private_key() -> X25519PrivateKey:
    """
    Load the server's long-term X25519 private key from Django settings.
    Cached after first load — avoids repeated settings lookups.
    """
    from django.conf import settings

    raw_b64 = getattr(settings, "SYNC_E2E_PRIVATE_KEY", "")
    if not raw_b64:
        raise RuntimeError(
            "SYNC_E2E_PRIVATE_KEY is not set in Django settings. "
            "Run keygen.py and add the private key to your settings."
        )
    raw = _b64d(raw_b64)
    return X25519PrivateKey.from_private_bytes(raw)


def _derive_session_key(shared_secret: bytes, nonce: bytes) -> bytes:
    """Mirrors client's _derive_session_key exactly."""
    return HKDF(
        algorithm = SHA256(),
        length    = _KEY_BYTES,
        salt      = nonce,
        info      = _HKDF_INFO,
    ).derive(shared_secret)


# ─────────────────────────────────────────────────────────────────────────────
# Public API
# ─────────────────────────────────────────────────────────────────────────────

class ServerSyncCrypto:
    """
    Server-side E2E crypto.  Two operations:

      decrypt_request(envelope)  → (plaintext_dict, session_key)
          Call at the top of sync_push / sync_pull views.
          Returns the decrypted payload dict and the session_key needed
          to encrypt the response.

      encrypt_response(data, session_key)  → envelope_dict
          Call just before returning Response() in sync views.
          Uses the same session_key from decrypt_request() so client
          can decrypt with the key it already has.
    """

    @classmethod
    def decrypt_request(cls, envelope: dict) -> tuple[dict, bytes]:
        """
        Decrypt an incoming push envelope from the client.

        Args:
            envelope: the parsed JSON body of the request

        Returns:
            (plaintext_dict, session_key)
            Keep session_key to encrypt the response with encrypt_response().

        Raises:
            ValueError: if envelope is malformed or decryption fails
        """
        # Validate protocol version
        version = envelope.get("v", 1)
        if version != _PROTOCOL_VERSION:
            raise ValueError(
                f"Unsupported E2E protocol version: {version}. "
                f"Expected {_PROTOCOL_VERSION}."
            )

        try:
            epk_bytes  = _b64d(envelope["epk"])
            nonce      = _b64d(envelope["nonce"])
            ciphertext = _b64d(envelope["ct"])
            tag        = _b64d(envelope["tag"])
        except KeyError as e:
            raise ValueError(f"Malformed E2E envelope — missing field: {e}") from e
        except Exception as e:
            raise ValueError(f"Malformed E2E envelope — bad base64: {e}") from e

        # Load server private key and derive shared secret
        server_priv       = _load_server_private_key()
        client_epk        = X25519PublicKey.from_public_bytes(epk_bytes)
        shared_secret     = server_priv.exchange(client_epk)

        # Derive session key — MUST use the nonce from the envelope (mirrors client)
        session_key = _derive_session_key(shared_secret, nonce)

        # AES-128-GCM decrypt
        aesgcm     = AESGCM(session_key)
        ct_and_tag = ciphertext + tag

        try:
            plaintext = aesgcm.decrypt(nonce, ct_and_tag, None)
        except Exception as e:
            # Catches InvalidTag — wrong key, tampered ciphertext, or wrong protocol
            raise ValueError(
                f"E2E decryption failed — authentication tag mismatch. "
                f"The payload may be tampered or the client used a stale server key. "
                f"Detail: {e}"
            ) from e

        try:
            data = json.loads(plaintext)
        except json.JSONDecodeError as e:
            raise ValueError(f"Decrypted payload is not valid JSON: {e}") from e

        logger.debug(
            f"[e2e] decrypted request — "
            f"ciphertext={len(ciphertext)}B plaintext={len(plaintext)}B"
        )
        return data, session_key

    @classmethod
    def encrypt_response(cls, data: dict | list, session_key: bytes) -> dict:
        """
        Encrypt a response payload using the session key from decrypt_request().

        The client can decrypt this with SyncCrypto.decrypt_response(envelope, session_key).

        A fresh nonce is generated for the response so that even though the
        same session_key is reused for request + response, the ciphertext
        and derived sub-key are different (GCM nonce uniqueness guarantee).
        """
        plaintext = json.dumps(data, separators=(",", ":")).encode()

        nonce      = os.urandom(_NONCE_BYTES)
        aesgcm     = AESGCM(session_key)
        ct_and_tag = aesgcm.encrypt(nonce, plaintext, None)
        ciphertext = ct_and_tag[:-16]
        tag        = ct_and_tag[-16:]

        envelope = {
            "v":     _PROTOCOL_VERSION,
            "nonce": _b64e(nonce),
            "ct":    _b64e(ciphertext),
            "tag":   _b64e(tag),
            # No "epk" in response — client already has the key from the request
        }

        logger.debug(
            f"[e2e] encrypted response — "
            f"plaintext={len(plaintext)}B ciphertext={len(ciphertext)}B"
        )
        return envelope

    @classmethod
    def decrypt_pull_request_header(cls, epk_b64: str) -> tuple[bytes, bytes]:
        """
        For pull requests: the client sends its ephemeral public key in the
        X-EPK header (no body to decrypt — it's a GET).

        Derives and returns (session_key, nonce) so the pull view can
        encrypt its response.

        Usage in sync_pull view:
            epk_b64 = request.headers.get("X-EPK", "")
            session_key, nonce = ServerSyncCrypto.decrypt_pull_request_header(epk_b64)
            # ... build response data ...
            envelope = ServerSyncCrypto.encrypt_response(data, session_key)
            return Response(envelope)
        """
        try:
            epk_bytes = _b64d(epk_b64)
            client_epk = X25519PublicKey.from_public_bytes(epk_bytes)
        except Exception as e:
            raise ValueError(f"Invalid X-EPK header: {e}") from e

        server_priv   = _load_server_private_key()
        shared_secret = server_priv.exchange(client_epk)

        # For pull, we generate a fresh nonce server-side for the response
        nonce = os.urandom(_NONCE_BYTES)
        session_key = _derive_session_key(shared_secret, nonce)

        return session_key, nonce